/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) {
        return 0;
    }

    // Collect all unique edge weights to use as potential thresholds
    const weights = new Set();
    for (const edge of edges) {
        weights.add(edge[2]);
    }

    // Sort unique weights and add 0 and a value larger than max weight for search space
    let sortedWeights = Array.from(weights).sort((a, b) => a - b);

    // Add 0 as the minimum possible threshold
    if (!sortedWeights.includes(0)) {
        sortedWeights.unshift(0);
    }
    // The largest possible threshold could be max(weights) or slightly more.
    // We search over the sorted unique weights, and check the range.

    // If there are no edges, and source != target, it's unreachable unless n=1, which is handled.
    if (edges.length === 0) {
        return -1;
    }

    // Add a sentinel value larger than any weight to cover the case where the optimal threshold
    // is larger than the maximum edge weight, but since we are looking for the minimum threshold,
    // searching over actual edge weights + 0 should suffice if we interpret the condition correctly.
    // If the optimal threshold T is such that all edges are 'light', then T >= max_weight.
    // We should test max(weights) + 1 effectively.
    const maxWeight = sortedWeights[sortedWeights.length - 1];
    if (maxWeight !== undefined && maxWeight !== 0) {
        sortedWeights.push(maxWeight + 1); // Test a threshold high enough to make everything light
    }


    /**
     * Checks if a path exists from source to target using at most k heavy edges 
     * when the threshold is `threshold`.
     * Uses a variation of BFS/Dijkstra's suitable for limited resource (heavy edges).
     * State: [node, heavy_edges_used]
     * @param {number} threshold
     * @returns {boolean}
     */
    const check = (threshold) => {
        const adj = Array(n).fill(0).map(() => []);
        for (const [u, v, w] of edges) {
            const isHeavy = w > threshold ? 1 : 0;
            // Store neighbor, weight, and heaviness (0 or 1)
            adj[u].push({ node: v, heaviness: isHeavy });
            adj[v].push({ node: u, heaviness: isHeavy });
        }

        // dist[i][j] stores the minimum number of heavy edges needed to reach node i 
        // while having used exactly j heavy edges so far. Wait, this is not right for shortest path.
        // We need to find if *any* path exists using <= k heavy edges.
        // State for BFS: [node, heavy_count]

        // visited[node][heavy_count] = true if this state has been reached
        const visited = Array(n).fill(0).map(() => Array(k + 1).fill(false));
        const queue = [];

        // Start state: (source, 0 heavy edges used)
        queue.push([source, 0]);
        visited[source][0] = true;

        let head = 0;
        while (head < queue.length) {
            const [u, currentHeavyCount] = queue[head++];

            if (u === target) {
                return true; // Found a valid path
            }

            for (const { node: v, heaviness } of adj[u]) {
                const newHeavyCount = currentHeavyCount + heaviness;

                if (newHeavyCount <= k && !visited[v][newHeavyCount]) {
                    visited[v][newHeavyCount] = true;
                    queue.push([v, newHeavyCount]);
                }
            }
        }

        return false;
    };

    // Binary Search on the possible thresholds (the sorted unique weights + 0, and one value larger than all)
    // We are looking for the minimum T such that check(T) is true.

    let low = 0;
    let high = sortedWeights.length - 1;
    let minThreshold = -1;

    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (check(currentThreshold)) {
            // currentThreshold works, try for a smaller threshold
            minThreshold = currentThreshold;
            high = midIndex - 1;
        } else {
            // currentThreshold is too small (or too restrictive), need a larger threshold
            low = midIndex + 1;
        }
    }

    return minThreshold;
}

